import pandas as pd
import re

businesses_with_wifi = locals()['var_function-call-17949206562872730360']
df_wifi_businesses = pd.DataFrame(businesses_with_wifi)

def extract_state(description):
    match = re.search(r'in ([A-Z]{2}),', description)
    if match:
        return match.group(1)
    return None

df_wifi_businesses['state'] = df_wifi_businesses['description'].apply(extract_state)
df_wifi_businesses_cleaned = df_wifi_businesses.dropna(subset=['state'])
state_counts = df_wifi_businesses_cleaned['state'].value_counts()

if not state_counts.empty:
    highest_state = state_counts.index[0]
    business_ids_in_highest_state = df_wifi_businesses_cleaned[df_wifi_businesses_cleaned['state'] == highest_state]['business_id'].tolist()
    result = {'highest_state': highest_state, 'business_ids': business_ids_in_highest_state}
else:
    result = {'highest_state': None, 'business_ids': []}

print('__RESULT__:')
print(pd.Series(result).to_json())

